def store_message_in_db(chat_id, role, content):
    """Сохраняет сообщение в базу данных и кэширует его в Redis."""
    conn = connect_to_db()
    cur = conn.cursor()

    # Сохраняем сообщение в базу данных
    cur.execute("""
        INSERT INTO chat_history (chat_id, role, content, timestamp)
        VALUES (%s, %s, %s, NOW())
    """, (chat_id, role, content))

    conn.commit()
    cur.close()
    conn.close()

    # Кэшируем сообщение в Redis
    cache_key = f'chat_history_{chat_id}'

    # Получаем текущую историю из кэша (если есть)
    history = r.lrange(cache_key, 0, -1)

    # Добавляем сообщение в историю и ограничиваем размер
    message = json.dumps({"role": role, "content": content})
    r.rpush(cache_key, message)

    # Ограничиваем размер кэша (например, до 100 сообщений)
    if r.llen(cache_key) > 100:
        r.lpop(cache_key)  # Удаляем старое сообщение

    print(f"Сообщение сохранено в базе данных и кэше Redis для chat_id {chat_id}.")

def get_chat_history(chat_id, limit=10):
    """Получает историю чата из Redis, если доступно, иначе из базы данных."""
    cache_key = f'chat_history_{chat_id}'

    # Попробуем получить историю из кэша
    history = r.lrange(cache_key, 0, limit - 1)

    if history:
        # Если история есть в кэше, возвращаем её
        print(f"История чата для chat_id {chat_id} получена из Redis.")
        return [json.loads(msg) for msg in history][::-1]  # Обратно в хронологическом порядке

    # Если в кэше нет, получаем из базы данных
    conn = connect_to_db()
    cur = conn.cursor()

    cur.execute("""
        SELECT role, content FROM chat_history
        WHERE chat_id = %s
        ORDER BY timestamp DESC
        LIMIT %s
    """, (chat_id, limit))

    history = [{"role": role, "content": content} for role, content in cur.fetchall()]

    cur.close()
    conn.close()

    # Сохраняем полученные сообщения в кэш
    for msg in history:
        r.rpush(cache_key, json.dumps(msg))
    
    # Ограничиваем размер кэша (например, до 100 сообщений)
    if r.llen(cache_key) > 100:
        r.lpop(cache_key)  # Удаляем старое сообщение

    print(f"История чата для chat_id {chat_id} получена из базы данных.")
    return history[::-1]  # Обратно в хронологическом порядке

def clear_chat_history(chat_id):
    """Очищает историю чата в базе данных"""
    conn = connect_to_db()
    cur = conn.cursor()
    cur.execute("DELETE FROM chat_history WHERE chat_id = %s", (chat_id,))
    conn.commit()
    cur.close()
    conn.close()


